// Both posts are `valid`, so their `@.dom()` covers every K (full domain).
// This makes the two views agree on their domains, which is one of the two
// premises Map's `=~=` extensionality needs.
post1_self_.valid_implies_complete();
post2_self_.valid_implies_complete();

// Pull all four `forall|ki|` ensures-conjuncts (two per run) into the proof
// context so z3 instantiates them on a common skolem `ki` rather than two
// disjoint ones — the original `unknown` is exactly this trigger gap.
assert(forall |ki:KeyIterator<K>|
    #[trigger] KeyIterator::between(lo, ki, hi)
        ==> post1_self_@[*ki.get()] == dst@);
assert(forall |ki:KeyIterator<K>|
    !ki.is_end_spec() && !(#[trigger] KeyIterator::between(lo, ki, hi))
        ==> post1_self_@[*ki.get()] == pre_self_@[*ki.get()]);
assert(forall |ki:KeyIterator<K>|
    #[trigger] KeyIterator::between(lo, ki, hi)
        ==> post2_self_@[*ki.get()] == dst@);
assert(forall |ki:KeyIterator<K>|
    !ki.is_end_spec() && !(#[trigger] KeyIterator::between(lo, ki, hi))
        ==> post2_self_@[*ki.get()] == pre_self_@[*ki.get()]);

// Pointwise on K: for every key, use `KeyIterator::new_spec(k)` as the
// witness that fires the `between(lo, ki, hi)` triggers above. A case split
// on `between` reduces to two sub-cases that are each immediate from the
// re-asserted foralls.
assert forall |k: K| post1_self_@[k] == post2_self_@[k] by {
    let ki = KeyIterator::<K>::new_spec(k);
    // `new_spec(k)` is `KeyIterator { k: Some(k) }`, so it is not the end and
    // `*ki.get()` unfolds to `k` (via the `open` `new_spec`/`get_spec` defs).
    assert(!ki.is_end_spec());
    assert(*ki.get() == k);
    if KeyIterator::between(lo, ki, hi) {
        // Both ensures' first conjunct fire on `ki`, giving
        // post1_self_@[k] == dst@ == post2_self_@[k].
    } else {
        // Both ensures' second conjunct fire on `ki` (it is not end), giving
        // post1_self_@[k] == pre_self_@[k] == post2_self_@[k].
    }
};

// Map extensionality: equal domains (full, from `valid_implies_complete`)
// plus pointwise value equality (just shown) lifts to view equality.
assert(post1_self_@ =~= post2_self_@);
assert(post1_self_@ == post2_self_@);
